$ErrorActionPreference = "Stop"
$Base = "C:\CleanSeedBuilds\CLEAN_SEED_PATCH_SCOPE_STATE_TRIGGER_LOCK"
$ActiveGuides = Join-Path $Base "ACTIVE_GUIDES"
$ProofHistory = Join-Path $Base "PROOF_HISTORY"
$LiveTest = Join-Path $Base "LIVE_SEED_TEST_001"

Write-Host "CLEAN SEED INSTALLER — SCOPE STATE TRIGGER LOCK"
Write-Host "Target: $Base"

if (Test-Path $Base) {
    $backupName = "_BACKUP_BEFORE_INSTALL_" + (Get-Date -Format "yyyyMMdd_HHmmss")
    $backupRoot = Join-Path $Base $backupName
    New-Item -ItemType Directory -Force -Path $backupRoot | Out-Null
    foreach ($folder in @("ACTIVE_GUIDES", "PROOF_HISTORY", "LIVE_SEED_TEST_001")) {
        $old = Join-Path $Base $folder
        if (Test-Path $old) {
            Copy-Item -Path $old -Destination (Join-Path $backupRoot $folder) -Recurse -Force
        }
    }
    Write-Host "PASS backup created for existing install: $backupRoot"
} else {
    New-Item -ItemType Directory -Force -Path $Base | Out-Null
    Write-Host "PASS created base folder: $Base"
}

foreach ($dir in @($ActiveGuides, $ProofHistory, $LiveTest)) {
    New-Item -ItemType Directory -Force -Path $dir | Out-Null
}

function Write-SeedFile {
    param(
        [string]$RelativePath,
        [string]$ExpectedSha256,
        [string[]]$Base64Lines
    )
    $dest = Join-Path $Base $RelativePath
    $destDir = Split-Path $dest -Parent
    New-Item -ItemType Directory -Force -Path $destDir | Out-Null
    $bytes = [Convert]::FromBase64String(($Base64Lines -join ""))
    [System.IO.File]::WriteAllBytes($dest, $bytes)
    $actual = (Get-FileHash -Algorithm SHA256 -Path $dest).Hash.ToLower()
    if ($actual -ne $ExpectedSha256.ToLower()) {
        throw "HASH FAIL: $RelativePath expected $ExpectedSha256 got $actual"
    }
    Write-Host "PASS wrote $RelativePath"
}

